    {"path": "uber-promo-code-generator/src/promo_generator.py", "content": "import random\nimport string\nfrom datetime import datetime, timedelta\nfrom typing import List, Optional\n\nclass PromoCodeGenerator:\n    \"\"\"Generates Uber promo codes with configurable patterns and validation.\"\"\"\n    \n    def __init__(self, prefix: str = \"UBER\", length: int = 8):\n        \"\"\"\n        Initialize the promo code generator.\n        \n        Args:\n            prefix: String prefix for promo codes (e.g., \"UBER\", \"RIDE\")\n            length: Total length of the code including prefix\n        \"\"\"\n        if not prefix.isalpha():\n            raise ValueError(\"Prefix must contain only letters\")\n        if length < len(prefix) + 4:\n            raise ValueError(\"Length must be at least prefix length + 4\")\n        self.prefix = prefix.upper()\n        self.length = length\n        self._generated_codes: set = set()\n    \n    def _generate_random_part(self, length: int) -> str:\n        \"\"\"Generate a random alphanumeric string of specified length.\"\"\"\n        chars = string.ascii_uppercase + string.digits\n        return ''.join(random.choices(chars, k=length))\n    \n    def generate_single(self) -> str:\n        \"\"\"\n        Generate a single unique promo code.\n        \n        Returns:\n            A unique promo code string (e.g., \"UBERX4K9M2\")\n        \"\"\"\n        suffix_length = self.length - len(self.prefix)\n        while True:\n            code = self.prefix + self._generate_random_part(suffix_length)\n            if code not in self._generated_codes:\n                self._generated_codes.add(code)\n                return code\n    \n    def generate_batch(self, count: int, expiry_days: Optional[int] = None) -> List[dict]:\n        \"\"\"\n        Generate a batch of promo codes with optional expiry.\n        \n        Args:\n            count: Number of codes to generate\n            expiry_days: Number of days until codes expire (None = no expiry)\n        \n        Returns:\n            List of dicts with 'code' and 'expires_at' keys\n        \"\"\"\n        codes = []\n        for _ in range(count):\n            code = self.generate_single()\n            promo = {\"code\": code, \"expires_at\": None}\n            if expiry_days:\n                promo[\"expires_at\"] = (datetime.now() + timedelta(days=expiry_days)).isoformat()\n            codes.append(promo)\n        return codes\n    \n    def validate_code(self, code: str) -> bool:\n        \"\"\"\n        Validate a promo code format.\n        \n        Args:\n            code: Promo code string to validate\n        \n        Returns:\n            True if code matches expected format, False otherwise\n        \"\"\"\n        if len(code) != self.length:\n            return False\n        if not code.startswith(self.prefix):\n            return False\n        suffix = code[len(self.prefix):]\n        return all(c in string.ascii_uppercase + string.digits for c in suffix)\n    \n    def reset(self) -> None:\n        \"\"\"Clear all previously generated codes (for testing).\"\"\"\n        self._generated_codes.clear()\n"},
    {"path": "uber-promo-code-generator/src/promo_applier.py", "content": "import json\nimport requests\nfrom datetime import datetime\nfrom typing import Optional, Dict, Any\n\nclass UberPromoApplier:\n    \"\"\"Simulates applying Uber promo codes via API (mock endpoint).\"\"\"\n    \n    def __init__(self, api_base_url: str = \"https://api.uber.com/v1\"):\n        \"\"\"\n        Initialize the promo applier with API base URL.\n        \n        Args:\n            api_base_url: Base URL for Uber API (default mock)\n        \"\"\"\n        self.api_base_url = api_base_url\n        self.session = requests.Session()\n        self.session.headers.update({\n            \"Content-Type\": \"application/json\",\n            \"User-Agent\": \"UberPromoGenerator/1.0\"\n        })\n    \n    def apply_promo(self, promo_code: str, user_id: str, discount_percent: float = 10.0) -> Dict[str, Any]:\n        \"\"\"\n        Apply a promo code to a user account (mock implementation).\n        \n        Args:\n            promo_code: The promo code string\n            user_id: User identifier\n            discount_percent: Discount percentage (default 10%)\n        \n        Returns:\n            API response dict with status and details\n        \"\"\"\n        payload = {\n            \"promo_code\": promo_code,\n            \"user_id\": user_id,\n            \"discount_percent\": discount_percent,\n            \"applied_at\": datetime.now().isoformat()\n        }\n        try:\n            response = self.session.post(\n                f\"{self.api_base_url}/promotions/apply\",\n                data=json.dumps(payload),\n                timeout=10\n            )\n            response.raise_for_status()\n            return response.json()\n        except requests.exceptions.RequestException as e:\n            return {\"status\": \"error\", \"message\": str(e), \"code\": promo_code}\n    \n    def check_promo_status(self, promo_code: str) -> Dict[str, Any]:\n        \"\"\"\n        Check the status of a promo code (mock).\n        \n        Args:\n            promo_code: The promo code to check\n        \n        Returns:\n            Status dict with usage count and expiry\n        \"\"\"\n        try:\n            response = self.session.get(\n                f\"{self.api_base_url}/promotions/{promo_code}\",\n                timeout=10\n            )\n            response.raise_for_status()\n            return response.json()\n        except requests.exceptions.RequestException as e:\n            return {\"status\": \"error\", \"message\": str(e), \"code\": promo_code}\n\nclass MockUberPromoApplier(UberPromoApplier):\n    \"\"\"Mock applier for testing without network calls.\"\"\"\n    \n    def __init__(self):\n        super().__init__(api_base_url=\"https://mock.api.uber.com/v1\")\n        self._applied_codes: Dict[str, Dict] = {}\n    \n    def apply_promo(self, promo_code: str, user_id: str, discount_percent: float = 10.0) -> Dict[str, Any]:\n        if promo_code in self._applied_codes:\n            return {\"status\": \"error\", \"message\": \"Promo code already used\", \"code\": promo_code}\n        self._applied_codes[promo_code] = {\n            \"user_id\": user_id,\n            \"discount_percent\": discount_percent,\n            \"applied_at\": datetime.now().isoformat()\n        }\n        return {\n            \"status\": \"success\",\n            \"message\": \"Promo code applied\",\n            \"code\": promo_code,\n            \"details\": self._applied_codes[promo_code]\n        }\n    \n    def check_promo_status(self, promo_code: str) -> Dict[str, Any]:\n        if promo_code in self._applied_codes:\n            return {\n                \"status\": \"active\",\n                \"code\": promo_code,\n                \"usage_count\": 1,\n                \"details\": self._applied_codes[promo_code]\n            }\n        return {\"status\": \"inactive\", \"code\": promo_code, \"usage_count\": 0}\n"},
    {"path": "uber-promo-code-generator/src/__main__.py", "content": "import sys\nimport argparse\nfrom src.promo_generator import PromoCodeGenerator\nfrom src.promo_applier import MockUberPromoApplier\n\ndef main():\n    \"\"\"Command-line interface for Uber promo code generator.\"\"\"\n    parser = argparse.ArgumentParser(\n        description=\"Uber Promo Code Generator - Generate and apply promo codes\"\n    )\n    parser.add_argument(\n        \"--generate\", type=int, metavar=\"N\",\n        help=\"Generate N promo codes\"\n    )\n    parser.add_argument(\n        \"--prefix\", type=str, default=\"UBER\",\n        help=\"Prefix for promo codes (default: UBER)\"\n    )\n    parser.add_argument(\n        \"--length\", type=int, default=8,\n        help=\"Total length of promo code (default: 8)\"\n    )\n    parser.add_argument(\n        \"--expiry\", type=int, metavar=\"DAYS\",\n        help=\"Expiry in days (optional)\"\n    )\n    parser.add_argument(\n        \"--apply\", type=str, metavar=\"CODE\",\n        help=\"Apply a promo code to a mock user\"\n    )\n    parser.add_argument(\n        \"--user\", type=str, default=\"test_user_123\",\n        help=\"User ID for applying promo (default: test_user_123)\"\n    )\n    \n    args = parser.parse_args()\n    \n    if not args.generate and not args.apply:\n        parser.print_help()\n        sys.exit(1)\n    \n    generator = PromoCodeGenerator(prefix=args.prefix, length=args.length)\n    applier = MockUberPromoApplier()\n    \n    if args.generate:\n        print(f\"Generating {args.generate} promo codes...\")\n        codes = generator.generate_batch(args.generate, expiry_days=args.expiry)\n        for promo in codes:\n            expiry_str = promo[\"expires_at\"] or \"No expiry\"\n            print(f\"  Code: {promo['code']} | Expires: {expiry_str}\")\n    \n    if args.apply:\n        print(f\"Applying promo code '{args.apply}' for user '{args.user}'...\")\n        result = applier.apply_promo(args.apply, args.user)\n        print(f\"  Status: {result['status']}\")\n        print(f\"  Message: {result.get('message', 'N/A')}\")\n\nif __name__ == \"__main__\":\n    main()\n"},
